import React, { useEffect, useState } from "react";
import axios from "axios";

const PriceList = () => {
  const [priceList, setPriceList] = useState([]);
  const [formData, setFormData] = useState({
    title: "",
    price: "",
    category: "",
  });
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(false);

  // ✅ Fetch all categories from backend
  useEffect(() => {
    const fetchCategories = async () => {
      try {
        const res = await axios.get("https://shreejighutargo21.onrender.com/api/category");
        if (res.data && Array.isArray(res.data)) {
          setCategories(res.data);
        } else if (res.data.data && Array.isArray(res.data.data)) {
          setCategories(res.data.data);
        } else {
          console.error("Unexpected category format:", res.data);
        }
      } catch (err) {
        console.error("Category fetch error:", err);
      }
    };
    fetchCategories();
  }, []);

  // ✅ Fetch all price list data
  useEffect(() => {
    const fetchPriceList = async () => {
      try {
        const res = await axios.get("https://shreejighutargo21.onrender.com/api/pricelist");
        if (res.data) setPriceList(res.data);
      } catch (err) {
        console.error("Price list fetch error:", err);
      }
    };
    fetchPriceList();
  }, []);

  // ✅ Handle input
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  // ✅ Submit new entry
  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post("https://shreejighutargo21.onrender.com/api/pricelist", formData);
      alert("Price added successfully!");
      setFormData({ title: "", price: "", category: "" });
      const res = await axios.get("https://shreejighutargo21.onrender.com/api/pricelist");
      setPriceList(res.data);
    } catch (err) {
      console.error("Error saving price:", err);
      alert("Failed to add price");
    }
    setLoading(false);
  };

  // ✅ Delete item
  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this item?")) return;
    try {
      await axios.delete(`https://shreejighutargo21.onrender.com/api/pricelist/${id}`);
      setPriceList(priceList.filter((item) => item._id !== id));
    } catch (err) {
      console.error("Error deleting item:", err);
    }
  };

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <h2 className="text-2xl font-bold mb-4 text-gray-800">📦 Price List</h2>

      {/* ✅ Add Form */}
      <form onSubmit={handleSubmit} className="bg-white p-5 rounded-xl shadow-md mb-6">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div>
            <label className="block font-semibold mb-1">Title</label>
            <input
              type="text"
              name="title"
              value={formData.title}
              onChange={handleChange}
              placeholder="Enter product title"
              className="w-full border p-2 rounded-md"
              required
            />
          </div>

          <div>
            <label className="block font-semibold mb-1">Price</label>
            <input
              type="number"
              name="price"
              value={formData.price}
              onChange={handleChange}
              placeholder="Enter price"
              className="w-full border p-2 rounded-md"
              required
            />
          </div>

          <div>
            <label className="block font-semibold mb-1">Category</label>
            <select
              name="category"
              value={formData.category}
              onChange={handleChange}
              className="w-full border p-2 rounded-md"
              required
            >
              <option value="">Select Category</option>
              {categories.length > 0 ? (
                categories.map((cat) => (
                  <option key={cat._id} value={cat._id}>
                    {cat.name || cat.title || "Unnamed Category"}
                  </option>
                ))
              ) : (
                <option disabled>Loading categories...</option>
              )}
            </select>
          </div>
        </div>

        <button
          type="submit"
          disabled={loading}
          className="mt-4 bg-blue-600 text-white px-5 py-2 rounded-md hover:bg-blue-700"
        >
          {loading ? "Saving..." : "Add Price"}
        </button>
      </form>

      {/* ✅ Price List Table */}
      <div className="bg-white shadow-md rounded-xl overflow-hidden">
        <table className="w-full border-collapse text-left">
          <thead>
            <tr className="bg-gray-200 text-gray-700">
              <th className="p-3 border">Title</th>
              <th className="p-3 border">Price</th>
              <th className="p-3 border">Category</th>
              <th className="p-3 border text-center">Actions</th>
            </tr>
          </thead>
          <tbody>
            {priceList.length > 0 ? (
              priceList.map((item) => (
                <tr key={item._id} className="border-b hover:bg-gray-50">
                  <td className="p-3 border">{item.title}</td>
                  <td className="p-3 border">₹{item.price}</td>
                  <td className="p-3 border">
                    {item.category?.name || item.categoryName || "N/A"}
                  </td>
                  <td className="p-3 border text-center">
                    <button
                      onClick={() => handleDelete(item._id)}
                      className="bg-red-500 text-white px-3 py-1 rounded-md hover:bg-red-600"
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="4" className="text-center p-4 text-gray-500">
                  No items found.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default PriceList;
